INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间卫生干净，服务很好，原来房间有一些小瑕疵，直接帮我们免费升级了房间，就是酒店', '房间卫生干净，服务很好，原来房间有一些小瑕疵，直接帮我们免费升级了房间，就是酒店比较老旧，周边交通很方便，地铁口就在酒店门口，酒店环境也非常好，早餐也可以', '2024-08-22', 4, '[''卫生状况'', ''前台服务'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0234312000f7hcczb307F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232812000f7hjtmk8ABA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234k12000f7het3k368F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '十分满意～', '十分满意～', '2025-01-01', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235j12000hj2vvd88CB9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232i12000hj2ymlj1360_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231w12000hj2cyzbB5F9_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '看了各个平台的评论加上有岭南金的会员卡才来订的酒店，但入住感觉很一般。入住时报了', '看了各个平台的评论加上有岭南金的会员卡才来订的酒店，但入住感觉很一般。入住时报了金卡会员号，前台没有任何关于金卡会员的介绍。客房没升级、免费早餐也不提、酒廊礼遇还是在我特意询问后才给了一张一个人的礼遇卡。什么欢迎水果，入住三天毛都没看见。我也是开了眼了！
但是酒店装潢很漂亮，公共设施维护很好。只是客房卫生间反味，房型过于紧凑。给娃买了毛绒纪念品，小姐姐得知我们不用开发票直接给我个人微信二维码让我缴费……呵呵了……', '2024-07-15', 3, '[''前台服务'', ''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231412000esiy95p883E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231h12000esiv6lbB05C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232m12000esiyvbpCC4F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232a12000esip2ax13F8_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境不错 但是价格有点高 里面有个博物馆 可以参观一下 总体还不错 缺点大堂没有', '环境不错 但是价格有点高 里面有个博物馆 可以参观一下 总体还不错 缺点大堂没有休息的地方', '2024-10-09', 4, '[''性价比'', ''整体满意度'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233d12000g22cdz1E57E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235112000g225hp56D78_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235j12000g224an25560_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '各区域的服务很细致', '各区域的服务很细致
早餐出品不错
房间整体不错，舒适干净，唯独空调有噪音大，但还可接受。
泳池的设施设备也还行，但少了些泳衣泳裤甩干服务（虽然有塑料袋配）
FO Rebecca & Chef Ricky very nice
酒店内的博物馆不错值得看看', '2024-07-15', 5, '[''整体满意度'', ''餐饮设施'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232112000esbhvmm0DE0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234m12000esbmerh1FBA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234312000esbgrx8C860_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233q12000esbn2pq2542_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234i12000esbrh7p7E51_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '金碧辉煌 园林幽雅', '金碧辉煌 园林幽雅', '2024-12-22', 5, '[''景观/朝向'']', '["[ \"https://dimg04.c-ctrip.com/images/0232q12000hcmb4wu48E4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232512000hckwgzyABE3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234612000hclystm5673_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236g12000hcm5vdf7D72_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店位置极佳，出门就是地铁，出行非常方便，酒店早餐的旋转餐厅也非常有特色，餐食丰', '酒店位置极佳，出门就是地铁，出行非常方便，酒店早餐的旋转餐厅也非常有特色，餐食丰富。酒店套餐中赠送的下午茶和欢乐时光，也很精致。', '2024-09-18', 4, '[''交通便利性'', ''餐饮设施'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0231112000fmnlo8hBC98_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236y12000fmncqc3C5FC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230z12000fmnmvu9E4E8_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '红棉双床房，房间很大，舒适，科技感十足，瀑布餐厅的自助早餐品种丰富，中西合璧，很', '红棉双床房，房间很大，舒适，科技感十足，瀑布餐厅的自助早餐品种丰富，中西合璧，很是可口。携程上买的套餐，很划算。', '2024-09-21', 5, '[''房间设施'', ''餐饮设施'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0230j12000foas5zg5422_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235z12000foaott8C6A3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232r12000foav5w11561_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231912000foaszsr9028_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常棒，服务非常好??', '非常棒，服务非常好??', '2024-12-18', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233t12000h9kmtig8183_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0233912000h9kqdwx2604_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店属罕见的城区花园式酒店，山水园林特别吸舒适，大堂辉煌有特色吸引眼球。借此', '花园酒店属罕见的城区花园式酒店，山水园林特别吸舒适，大堂辉煌有特色吸引眼球。借此机会还参观了博物馆了解酒店的历史底蕴。每到一处服务人员都很温柔礼貌，细心体贴。感谢酒店前台Gillian免费升级了红棉大房，还赠送了下午茶，如果房间能见到园林就更好了。下次还是会入住。', '2024-07-14', 5, '[''整体满意度'', ''前台服务'', ''景观/朝向'']', '["[ \"https://dimg04.c-ctrip.com/images/0234i12000es36dqeD570_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230912000es38e1iDB24_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230s12000es2zrep9E44_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231v12000es36mek2A8F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235q12000es35ndjC675_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232812000es341tx69BA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235d12000es36rfp2D1F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231f12000es33hq59620_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234i12000es37r6052DE_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '带父母和宝宝休假，房间无烟很安静，但空调口上方的墙壁发霉了没有清理。楼层房间的清', '带父母和宝宝休假，房间无烟很安静，但空调口上方的墙壁发霉了没有清理。楼层房间的清洁阿姨和服务人员特别好。桃园馆的早茶的牛奶因为天气热了有点发酸，没有宝宝的餐具提供，而且有一个穿深蓝色西装的**男领班不会收餐盘，上水果时因为桌上有很多宝宝用过的纸巾和空盘子，当着客人的面很为难和不耐烦的叹气，好像不知道怎么处理似的，还需要我主动把一个空盘子递给他拿走才处理好，令人感觉很不舒服，服务意识和水平很低。服务细节需要提高培训。瀑布餐厅和荔湾亭的餐食和服务很满意，宝宝正在好动的年纪，但服务员对宝宝很有耐心，有很高的服务意识，餐食也很新鲜美味。前期打酒店电话预约时感觉接电话的服务人员和餐厅沟通协调不是很好，没有及时帮忙预约餐厅位置。到店后遇到的服务人员总体还不错。', '2024-07-20', 4, '[''客房服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234d12000eudc7dz78F7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231l12000eudeojlE37A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236h12000eudlpjhB58D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '带两个小孩 询问后给升级了房型 酒店很漂亮很高大上 早餐也很丰盛 各个服务员态度', '带两个小孩 询问后给升级了房型 酒店很漂亮很高大上 早餐也很丰盛 各个服务员态度都很友善 笑脸相迎 很愉快的体验 有机会还是会选择这个酒店', '2024-08-27', 5, '[''整体满意度'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233u12000f9i3e1l8F60_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236c12000f9hp10v72A5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235y12000f9hkj6k9058_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232q12000f9ia2aj2D20_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234012000f9hw9439CA1_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好', '好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好', '2024-09-16', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0203h12000fl9iiu99657_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0204w12000fl9jpsg19AC_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0201z12000fl9itbd4AB5_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0230u12000fl8xbj64E67_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230b12000fl98iie1204_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231n12000fl94cl56CA6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '太满意了，性价比极高，服务巨好。体验感极佳，行政酒廊的小姐姐（名字如图）又漂亮又', '太满意了，性价比极高，服务巨好。体验感极佳，行政酒廊的小姐姐（名字如图）又漂亮又温柔，客房，硬件都非常优秀！住了2晚换了希尔顿，后悔中……', '2024-08-28', 5, '[''性价比'', ''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236912000faf6zecE545_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233z12000faf6y0q1ED9_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州花园酒店，一家有着历史文化感的酒店，一家来了后会让你惊艳的酒店，一家需要专业', '广州花园酒店，一家有着历史文化感的酒店，一家来了后会让你惊艳的酒店，一家需要专业讲解的酒店，一步一景，从金碧辉煌的大堂壁画到瀑布餐厅，后花园，到酒店自带的博物馆，都给人无限惊喜。床品很舒适，睡的很舒服，酒店服务很周到，给我们送了早餐和下午茶。特别感谢三十楼旋转餐厅的CARRIE和大堂的HENRY（带我们一路参观讲解酒店的历史文化景致，孩子很喜欢听）。总之，很值得入住的一家老牌酒店，适合亲子家庭出游入住，下次来还会选择。', '2024-07-10', 5, '[''整体满意度'', ''公共设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232h12000eqmxhqz46DB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231x12000eqmxtym28BE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236m12000eqmxg1rBB08_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231i12000eqmxqgu99D4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233p12000eqmy7dvFBF2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230312000eqmxumnB71D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232312000eqmy7ge6D9F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '偶然花园暑假推出特惠套餐，时隔几年再次带妹来打卡，非常惊喜，推出打卡点活动，参观', '偶然花园暑假推出特惠套餐，时隔几年再次带妹来打卡，非常惊喜，推出打卡点活动，参观酒店博物馆，晚上在荔湾亭任点任食茶点，早上望着瀑布品尝丰富早餐，一系列活动令行程丰富多彩，宝宝乐而忘返', '2024-07-21', 5, '[''餐饮设施'', ''整体满意度'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232w12000eupf8vxA8F5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234a12000eupd8y9013C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236s12000eupfw0q3E1B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务我真的是想打超五星的评价，太贴心了，非常友好。', '服务我真的是想打超五星的评价，太贴心了，非常友好。
不过确实毕竟是老酒店，电话坏了我一直打不通联系不到前台，只能使用自己的手机，报姓名确认身份。
我们是带娃入住，说明之后准备了儿童拖鞋以及洗浴用品，非常感谢。离开的时候因为我们带娃涉及到睡午觉还给我们延迟退房到2:00。
总体我觉得是性价比很高～从入住到离开感受到了五星服务。', '2024-07-10', 5, '[''前台服务'', ''客房服务'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0232s12000eqmk4uq90D0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州的老品牌高档酒店，商务出差，来到这里下榻。总体的感觉还是挺不错的，大堂富丽堂', '广州的老品牌高档酒店，商务出差，来到这里下榻。总体的感觉还是挺不错的，大堂富丽堂皇，房间干净清新，只是房内的设施稍显陈旧，客房大楼没有负一负二层，得到另外一个地下停车场停车，其他都挺好的。', '2024-07-15', 5, '[''房间设施'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0235012000esfoxpf02B0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234y12000esfoni2C76C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232w12000esfomcgB461_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间插头很少，电视遥控极简模式很不方便操作。', '房间插头很少，电视遥控极简模式很不方便操作。', '2024-11-14', 3, '[''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232w12000goccmhz5B9F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231l12000goccnli1E90_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常满意的一次住宿体验，原本是为了酒店中的米其林餐厅来的，从到店接待的服务，每日', '非常满意的一次住宿体验，原本是为了酒店中的米其林餐厅来的，从到店接待的服务，每日清洁服务，多样化的早餐选择都让我重新认识了花园酒店，酒店自有的博物馆让我非常震撼。', '2024-08-03', 5, '[''餐饮设施'', ''前台服务'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0230s12000ezrabygC76F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230p12000ezrad62AD45_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231i12000ezrajup2BB4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231n12000ezrad719633_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235e12000ezral512444_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233712000ezraph41628_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230412000ezral5mC5B8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233h12000ezrak2b0700_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235v12000ezraq2sEAAC_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '带着父母入住，他们很满意，宾至如归。碰巧是我自己的生日，酒店给的情绪价值也是非常', '带着父母入住，他们很满意，宾至如归。碰巧是我自己的生日，酒店给的情绪价值也是非常到位了，谢谢。
停车很方便。员工也很礼貌。', '2024-09-05', 5, '[''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0230r12000feycrr694E9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235612000fey6eglA3A5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236212000fey6egn4926_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234712000feyjocbBA0F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236x12000fey5a6mE203_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间干净卫生，细节满满，还有文具盒。有??还提供浴盐，拖鞋很舒服。酒店内设计有博', '房间干净卫生，细节满满，还有文具盒。有??还提供浴盐，拖鞋很舒服。酒店内设计有博物馆很有特色。后花园很大很漂亮。赠送的小羊玩偶很可爱??', '2024-08-25', 5, '[''房间设施'', ''卫生状况'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230f12000f8xh0kw3C7E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230x12000f8xgtad254C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236c12000f8xn1gw1738_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236712000f8xgdwk141D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234k12000f8xkr0l2895_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233m12000f8xn11sE409_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236712000f8wz9kj3E07_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '年味超浓~交通便利~后花园儿环境优美~下次来广州还住这里。', '年味超浓~交通便利~后花园儿环境优美~下次来广州还住这里。
前台瑞贝卡特别nice，服务特别耐心细致~', '2025-01-30', 5, '[''整体满意度'', ''交通便利性'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236q12000i5zc8n2215C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236o12000i5z9pvy68AA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237212000i5z54o1732A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237312000i5ybjmpDFEB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232n12000i5yaeaz6C5B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '昨天交通很便利，门口就有地铁。服务非常周到，每层都有服务员。购买的套餐在楼顶的旋', '昨天交通很便利，门口就有地铁。服务非常周到，每层都有服务员。购买的套餐在楼顶的旋转餐厅吃早餐感觉很好。后面有一个很大的很美的花园。', '2024-10-10', 5, '[''交通便利性'', ''餐饮设施'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0230b12000g2r8limD094_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236k12000g2r5qs046E3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233z12000g2rvqu3C73D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '?? 广州花园酒店——一场无与伦比的入住体验 ??', '?? 广州花园酒店——一场无与伦比的入住体验 ??
 
朋友们，我刚从广州花园酒店回来，心情还沉浸在那无比美妙的时光里！必须要跟大家分享一下我这次超赞的入住经历！
 
当我踏入广州花园酒店的那一刻，就仿佛走进了一个充满魅力和故事的世界。酒店那悠久的历史气息扑面而来，每一处细节都仿佛在诉说着过去的辉煌，让我心生敬畏和好奇。
 
不得不提的是酒店的博物馆，这简直是一个隐藏的宝藏！在那里，我仿佛穿越了时空，领略到了酒店一路走来的风风雨雨，以及背后蕴含的深厚文化底蕴。那些珍贵的展品、精彩的介绍，让我对这座酒店有了更深层次的认识和理解。
 
而行政酒廊更是给我带来了惊喜不断！舒适优雅的环境，丰富多样的饮品和小吃，每一口都是极致的享受。在这里，我可以放松身心，尽情地享受属于自己的惬意时光。特别是主管carrie，美丽的印度小姐姐（周三还有来自尼泊尔的Kanchan小姐姐），提供了非常好的服务，happy hour的氛围很好，人也不多，顶楼可以看到广州老的CBD环市东的风景
 
但最让我感到温暖和满意的，还是酒店工作人员那无与伦比的热情态度。从进门的那一刻起，每一个微笑、每一句问候，都让我感受到了家一般的亲切。他们总是能在第一时间满足我的需求，无论是解答疑问还是提供帮助，都表现得专业而贴心。
 
还有酒店那美丽的花园！漫步其中，花香四溢，绿树成荫，仿佛置身于人间仙境。在这里，我可以暂时忘却外界的喧嚣和烦恼，尽情地享受大自然的恩赐。
 
总之，在广州花园酒店的这次入住体验，无论是硬件设施还是软件服务，都堪称完美。我真的非常喜欢这里，已经迫不及待地想要再次回来！强烈推荐给大家，相信你们也一定会爱上这个充满魅力的地方！', '2024-07-09', 5, '[''整体满意度'', ''前台服务'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233p12000eq7xlwm4875_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236h12000eq827m03F7E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234n12000eq8249fB2FE_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间有点小，床品不错，还贴心地提供了荞麦枕。服务一如既往地好。', '房间有点小，床品不错，还贴心地提供了荞麦枕。服务一如既往地好。', '2024-10-25', 4, '[''房间设施'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232f12000gb6zjwhD03C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231f12000gb66npi1A30_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231t12000gb6t43c9B00_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '进门的香水味有点浓，外宾比较多，工作人员服务还不错，房间卫生也不错，隔音我觉得没', '进门的香水味有点浓，外宾比较多，工作人员服务还不错，房间卫生也不错，隔音我觉得没有其他评价说的那么差，位置也方便，就是开窗需要工作人员来开比较麻烦。', '2024-08-13', 4, '[''前台服务'', ''卫生状况'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235o12000f3wiv4g3E88_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '感觉这酒店是给歪果仁开的', '感觉这酒店是给歪果仁开的
服务很一般（清扫服务员除外）
台灯坏了，打电话半天没人接，接了态度也不好，来人换灯进门不打招呼换完带有怨气的走了
硬件设施不错，估计这也是评上金榜的原因
但是房间一般，泳池一般，服务员高高在上。。。
瀑布餐厅更是可笑，明明他能去抢，但是他偏偏给你安排了一个外面摊位味道都不如的自助餐给你换钱', '2024-07-05', 4, '[''前台服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232r12000eotj6cv1372_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店虽然经常光顾荔湾亭餐饮，住房还是头一次。酒店服务的确不错，无论进大堂门口', '花园酒店虽然经常光顾荔湾亭餐饮，住房还是头一次。酒店服务的确不错，无论进大堂门口，还是礼宾部，再进服务台前的礼仪小姐到服务台的登记，都是笑脸相迎，中途叫外卖在礼宾部那里收货，站开关门的小姐姐看到我行动不太方便主动帮忙提上客房，特别的感动。21楼兰英客房服务员每天不辞辛劳的打扫卫生，每每出去游玩回来之后，都有宾至如归的感觉。十天的旅游行程转眼就过去，到了退房时间，一大早21楼朱小姐的迎送、礼宾部刘先生帮忙把行李拿到礼宾部暂存，酒店无论是环境还是接待，都是一流的服务质量，下次有机会还是我首选的住宿地方。设施虽陈旧一点，其他都很好。', '2024-08-27', 5, '[''前台服务'', ''客房服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0205v12000f9jyltb78CF_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0233112000f9ivqwp4043_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236d12000f9ive4b9421_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232s12000f9j0j0d7904_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234412000f9jmykhE367_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232412000f9j1unjF141_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '升级住了红棉双床房，房间很大，送的迎宾点心很精致。酒店的环境非常好，玩携程铂金的', '升级住了红棉双床房，房间很大，送的迎宾点心很精致。酒店的环境非常好，玩携程铂金的行政酒廊在30楼旋转餐厅，早餐非常丰富，下午有点心水果和饮料。行政酒廊的Carrie是印度人，中文讲得很好，也非常热情。', '2024-08-05', 5, '[''餐饮设施'', ''整体满意度'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232t224x8vufbnce2813_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231x224x8vuegeyf3D9E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234b224x8vuen1a2FABE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230s224x8vuep9bn4FC1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231r224x8vued9qr8061_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230h224x8vuecxd03E63_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234b224x8vudnycr89FF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233d224x8vueaib31500_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '各方面都不错，有很多打卡点！大堂壁画和中国风的文化装饰值得体验！更值得惊艳的是藏', '各方面都不错，有很多打卡点！大堂壁画和中国风的文化装饰值得体验！更值得惊艳的是藏在酒店里的博物馆！令本土广州人回忆了一把！', '2024-08-28', 5, '[''公共设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230r12000fa87mhq07BB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236412000fa87t0w1FC2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236q12000fa87vbcF154_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '十一假期在花园酒店度过了两个晚上，我们一家都觉得很满意，以后有机会还会继续入住。', '十一假期在花园酒店度过了两个晚上，我们一家都觉得很满意，以后有机会还会继续入住。', '2024-10-04', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230512000fyhn74iD916_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232r12000fyiqmme15CD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230y12000fyivqajF1F7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236612000fyian0sBEF4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236h12000fyirh7fA5C1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231x12000fyhn74m92FC_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务满分，酒店活动送的小羊很可爱，自带的花园很漂亮，早餐也不错。掉了一根电源线在', '服务满分，酒店活动送的小羊很可爱，自带的花园很漂亮，早餐也不错。掉了一根电源线在酒店马上联系我快递过来，体验感很棒。', '2024-09-01', 5, '[''前台服务'', ''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231l12000fc4xnph9088_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230s12000fc4sdj84089_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230512000fc51yo33BEF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231312000fc52rnx3E65_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间很干净不错，床非常柔软舒适，整个酒店的人员服务非常到位（点名echo哦！），', '房间很干净不错，床非常柔软舒适，整个酒店的人员服务非常到位（点名echo哦！），不愧是白金五星酒店，感觉服务人员比宾客还要多！', '2024-08-25', 5, '[''整体满意度'', ''房间设施'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0230x12000f8x73tqDCE9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232a12000f8x8eid6BF8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235s12000f8x3a0yAE0F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234912000f8xadqwD2D8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231w12000f8x9q0b6EEE_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务：很体贴 虽然办理入住时有点麻烦 但后期都解决', '服务：很体贴 虽然办理入住时有点麻烦 但后期都解决

卫生：很干净中午办理的入住 都能及时打扫干净

设施：已经是老牌的五星酒店了 以往我更偏向对于新的酒店 这次是朋友要来临时找的 起初还是有点担心 但入住过后发现很棒 所以说酒店设施各方面无论不关岁月长短 跟管理层很大关系 为你们点赞????
环境：如若有点不怎么喜欢的是花园那块 环境幽雅但就是太多网红了 想去休息逛逛一堆网红在拍拍', '2024-07-01', 5, '[''前台服务'', ''卫生状况'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233d12000en08i8o3ED3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235h12000en0kkxpA97F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234h12000en0n9v8BF8D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店公共设施装修的很好，酒店工作人员非常礼貌、周到??，连按电梯都有专门服务，我', '酒店公共设施装修的很好，酒店工作人员非常礼貌、周到??，连按电梯都有专门服务，我们准备 中午十二点退房时，航司短信提示延误 2 个小时，酒店特意安排我们可以延迟退房，这个太贴心了??????。但是缺点还是要说的，客房内部装修有点老，希望酒店能够将客房内部装修再提升下，以后再来还会选择入住。', '2024-07-01', 4, '[''前台服务'', ''公共设施'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235t12000en2x7fp4962_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231j12000en36zfx31F4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231c12000en2xglqBEB6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店大堂富丽堂皇，服务宾至如归，有人主动帮忙提行李，开门，连电梯口也有服务员帮忙', '酒店大堂富丽堂皇，服务宾至如归，有人主动帮忙提行李，开门，连电梯口也有服务员帮忙按电梯，前台的小姐姐isabella不仅人漂亮热情服务周到，而且还帮我升级了房间，太开心啦！以后过来旅游还会住这家酒店的。', '2024-07-12', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233t12000erfil4v9C0C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232912000erfh7lr543E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234g12000erfeob6EA21_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '前台小姐姐Viria人超nice，看到小朋友免费升级了房间还赠送了小朋友的早餐，', '前台小姐姐Viria人超nice，看到小朋友免费升级了房间还赠送了小朋友的早餐，房间也很干净整洁大气，花园酒店博物馆也很有意思，酒店充满中国传统文化和西方文化元素的完美融合，金光闪闪的太豪了，还有很多好吃的餐厅，很棒！', '2024-06-30', 5, '[''前台服务'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0230r12000emp86zr8427_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233112000emp794a7E92_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232k12000emp8ig8B659_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232d12000emp003p49B2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236112000emp4axfF0A7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231n12000emp86zt6068_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '床垫很舒适，房间也很安静！入住过很多次了，很多房型都住过，每次去体验感都非常棒！', '床垫很舒适，房间也很安静！入住过很多次了，很多房型都住过，每次去体验感都非常棒！下次还会选择推荐！', '2024-09-14', 5, '[''房间设施'', ''安静程度'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233512000fk4gbuh0010_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '3楼的旋转餐厅是亮点，每次出差我都住花园酒店，接待都是外籍加英文服务 非常国际化', '3楼的旋转餐厅是亮点，每次出差我都住花园酒店，接待都是外籍加英文服务 非常国际化，老牌广州高端酒店，周边餐馆也很多', '2024-09-03', 5, '[''餐饮设施'', ''前台服务'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0232q224x8w7b7busA518_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230d224x8w78d33j0CDB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这次入住广州花园酒店体验超棒！必须夸夸前台的Rem。从踏入酒店的那一刻起，Rem', '这次入住广州花园酒店体验超棒！必须夸夸前台的Rem。从踏入酒店的那一刻起，Rem就热情相迎，脸上洋溢着真诚的笑容，瞬间驱散了旅途的疲惫。办理入住时，他业务非常熟练，快速又高效地处理好了各项手续，还耐心解答我各种问题，给出游玩和用餐建议。Rem用专业与热忱诠释优质服务，让我有宾至如归之感，下次还选广州花园酒店 ，也期待再遇Rem ！', '2025-03-21', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233e12000j7rmks94254_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间非常干净。特别是前台小姐姐吴灵玲的服务非常令我感到满意??，让我体会到宾至如', '房间非常干净。特别是前台小姐姐吴灵玲的服务非常令我感到满意??，让我体会到宾至如归的感觉。给她点个赞！', '2024-09-19', 5, '[''前台服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0231512000fn5m8c67212_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '之前看评价，说有什么霉味，心中有些许忐忑，结果到达第一天，踏进酒店的第一步就消除', '之前看评价，说有什么霉味，心中有些许忐忑，结果到达第一天，踏进酒店的第一步就消除了所有顾虑，前台工作人员Vann（不知道名字是否正确？）帮忙升级了两间房，房间非常漂亮舒适，设施也很齐全，房间收拾的非常精致干净，工作人员也很友好，几乎每层楼都有工作人员帮忙按电梯，入住非常满意！后来因为航班取消，因为有老人，跟酒店商量，原房续住，工作人员很快速地帮忙协调解决，非常感谢！酒店的后花园环境很好，就是蚊子有点生猛，哈哈??', '2024-06-25', 5, '[''前台服务'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0232112000ekpgsi58683_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231612000ekph1tm6E6C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232x12000ekpgsi714F7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234q12000ekpgcapE923_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233312000ekpdmvl4626_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235o12000ekph2h89CA1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233z12000ekpdmvn2AAB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境：酒店就在地铁口附近，很方便。酒店外部环境和内部装修陈列很讲究的。酒店外被绿', '环境：酒店就在地铁口附近，很方便。酒店外部环境和内部装修陈列很讲究的。酒店外被绿色的植物包围和点缀，自然和谐；酒店内部随处可见的艺术品和讲究的装修设计，更让我对这家酒店有了新的认识。
设施：虽然开业很久，但是维护很好，根本不像其他老酒店一样，用陈旧的设施和老气装修来体现酒店“年代”和“经典”。各种设施设备配套很完善，不过还是有一点意外房间客厅电视屏幕有问题，希望及时检查维修；房间衣柜门开关的凹槽位置太锋利了，很容易划破手。
服务：从大堂的迎宾，到电梯口的员工，让这份服务从进入酒店就开始了，感觉无处不在。但是，好像去早了没房间，规定必须两点入住，无论是节假日还是工作日，去早了就要被 upsell ，虽然没多少钱，但是好像别人替我已经做好了选择。已经有点累了，还是加钱升级了，入住后才看到别人的会员金卡原来可以免费升级。
其他：早餐选择比较多，旋转餐厅景色也很好。
总的来说我很建议外地来广州的朋友去体验一下，感受来说比万豪希尔顿凯悦不一样，纯住宿角度来说也比白天鹅更推荐。', '2024-06-26', 4, '[''交通便利性'', ''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232312000ekudkvk5E46_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235o12000eku8yjgF0C4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236912000eku4txn1F84_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230812000ekub8wyA9D7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235412000eku9ge3E2D9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230b12000ekudapd2DFA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232n12000eku2mtq5422_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231012000eku9o6g75EB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '家庭出游，订的套餐，服务非常好，提前打电话准备好房间，提醒天气情况。早餐偏西式，', '家庭出游，订的套餐，服务非常好，提前打电话准备好房间，提醒天气情况。早餐偏西式，选择在瀑布餐厅，餐后后花园散散步，很惬意。', '2024-08-22', 5, '[''前台服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231s12000f7i587dBE7C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230z12000f7itxdi9846_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233n12000f7ivra5FBA2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州有点热，客房服务很贴心多准备了饮用水。第一天看演唱会，第二天出去玩原本回来想', '广州有点热，客房服务很贴心多准备了饮用水。第一天看演唱会，第二天出去玩原本回来想问客房多要几瓶水的，没想到都准备好了，非常满意。酒店很漂亮，出行便捷，门口就有地铁站。', '2024-07-21', 5, '[''客房服务'', ''交通便利性'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0237412000eunv3f800FB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234312000eunz5zb0C01_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233912000eunwhznEFAB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232g12000euo6lad144E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '在预定前就了解到花园酒店的背景，也考虑到酒店因为装修比较老旧可能会有一些体验上的', '在预定前就了解到花园酒店的背景，也考虑到酒店因为装修比较老旧可能会有一些体验上的不足。但实际入住后觉得一直被惊喜到。酒店迎宾很体贴，能看到我（其实并未主动提出）的特殊入住需求，也给了很多实用建议。房间虽然不大，也没有智能马桶，但对我提出要除湿机马上就能响应。酒店的早餐很惊艳，虽说是网红餐厅但并没有因为客人众多而服务有任何缺失，其他餐厅预定也很方便。一层的花园人非常少，吃完早餐去溜达一下很悠闲。酒店位置也非常便利，出门就是地铁，周围都是餐厅，不想出门就订外卖，外卖柜位置虽然隐秘但知道在哪里后就挺好找的。', '2024-06-30', 4, '[''前台服务'', ''餐饮设施'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0234j12000emsnbm08233_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233412000emslgbm2CE3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231s12000emscou3CCA6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常好的老牌五星级大酒店，前台接待服务非常热情，房间干净整洁。离地铁站非常近出行', '非常好的老牌五星级大酒店，前台接待服务非常热情，房间干净整洁。离地铁站非常近出行非常便捷，小孩在游泳池游泳体验非常好。', '2024-10-19', 5, '[''前台服务'', ''交通便利性'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0232d12000g7u1v943257_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233a12000g7tlj8mBC29_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233o12000g7u8v9p17EA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '挺不错的，下次还会住这里??', '挺不错的，下次还会住这里??', '2024-11-20', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235k12000grzn7cf0925_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233812000grzog1p7B7F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236n12000gryr2u83B33_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务一级棒，两间房给换成套房，28楼视野无敌。国庆出游，体验感很不错。', '服务一级棒，两间房给换成套房，28楼视野无敌。国庆出游，体验感很不错。', '2024-10-03', 5, '[''前台服务'', ''景观/朝向'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234x12000fxyeopbF50F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234212000fxz9x9u8905_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '40年的酒店，外观很久。', '40年的酒店，外观很久。
里面大气，设施房间一流。
服务更是很棒，老钱风的高水准。
特别是行政酒廊，服务热情主动，谢谢@Kitty。', '2024-08-09', 4, '[''房间设施'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230d12000f23lxh414B2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230812000f23lvp965F6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州美到可以封神的酒店！', '广州美到可以封神的酒店！
艺术，文化，自然和美食，均可在此领略。', '2024-10-06', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236m12000g0lptfvFD42_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0235v12000g0ln1cfAD2E_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0232z12000g0lrfry9EB8_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0236e12000g0lrxukF730_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0235p12000g0lqtgd4E48_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店位置就在地铁口附近，出行方便，大堂非常漂亮，很多外宾住在这里，工作人员也有很', '酒店位置就在地铁口附近，出行方便，大堂非常漂亮，很多外宾住在这里，工作人员也有很多是老外，中文很英文都很好，服务态度也非常好', '2024-08-14', 5, '[''交通便利性'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232r12000f45b68cBF4C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235y12000f458vqyF22F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231912000f45f6zrF33F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务非常周到、环境优美，还给免费升级了行政套房、赠送了两张早餐卷。', '服务非常周到、环境优美，还给免费升级了行政套房、赠送了两张早餐卷。', '2024-10-04', 5, '[''前台服务'', ''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233512000fzaqmmk2849_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233p12000fzalek0E97E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234412000fza7wboBDF9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235g12000fzanhpl43DD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232j12000fzapntiAC8F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '设施：卫浴设施有点老旧，尤其是卫生间，冲水的时候总觉得水阀要坏了。', '设施：卫浴设施有点老旧，尤其是卫生间，冲水的时候总觉得水阀要坏了。

卫生：整体还不错
环境：很好，饭后在酒店里逛逛，当散步 
服务：服务员都很好，很细致很热心，看起来培训到位。', '2024-07-03', 4, '[''房间设施'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0233j12000enzmq5fB1FC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232z12000enzn2x155B5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232t12000enzkmkd3904_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231712000enzrf9x7CA6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230v12000enzmlzkE91B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234l12000enzuwml1B32_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店大堂奢华，房间设施就过得去，房间略显成就，送下午茶点心', '酒店大堂奢华，房间设施就过得去，房间略显成就，送下午茶点心', '2024-10-31', 4, '[''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233812000gen57iiFD7D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230212000genhiujED19_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230y12000genhiulB3CB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231i12000genfsy3AD0E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233l12000gemryx2052E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234412000gengrjm2D4F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这次的酒店套餐活动非常好??房间干净整洁，早餐也很好吃，行政酒廊欢乐时光小食丰富', '这次的酒店套餐活动非常好??房间干净整洁，早餐也很好吃，行政酒廊欢乐时光小食丰富，Carrie、Berlye服务很好', '2024-08-20', 5, '[''餐饮设施'', ''卫生状况'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0233h12000f6ua8ru25AA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232612000f6u0qro9102_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236t12000f6uel8oC72A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '周末带小朋友玩，第二次来花园酒店，服务一如既往的好，有花园小桥流水，有丰盛的自助', '周末带小朋友玩，第二次来花园酒店，服务一如既往的好，有花园小桥流水，有丰盛的自助餐，空中旋转餐厅，还有沉淀历史文化的博物馆，', '2024-10-03', 5, '[''餐饮设施'', ''整体满意度'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232c12000fxj111rE900_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233y12000fxixcb12B13_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233312000fxi75xg52BF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230312000fxj4rk58623_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231b12000fxiv6qy762D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231l12000fxiga4a248F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '前台服务很热情，大堂造型很顶，入住时才知道花园酒店是中国三家白金五星酒店之一，还', '前台服务很热情，大堂造型很顶，入住时才知道花园酒店是中国三家白金五星酒店之一，还有个酒店博物馆。整体感觉不错。', '2024-08-24', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233r224x8w26llli14ED_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02323224x8w28gvji3736_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231q224x8w29k1v127E4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '前台生小姐妹态度很好，帮我升级了套房，送了行政下午茶 可惜只送了我这个岭客汇会员', '前台生小姐妹态度很好，帮我升级了套房，送了行政下午茶 可惜只送了我这个岭客汇会员，总体是一次很不错的旅行。', '2024-09-16', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0201z12000flam6tr9FD2_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0236912000flal6hyC2BD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230212000flal6i0B70D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236212000fl9pcno5662_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232e12000fla5zfb3256_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230o12000flafgeg0140_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234h12000flakdiyCF07_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌五星级酒店，细节很有特色和文化底蕴，早餐在一楼和三十楼都可以，菜品很丰富，三', '老牌五星级酒店，细节很有特色和文化底蕴，早餐在一楼和三十楼都可以，菜品很丰富，三十楼的旋转餐厅可360度观景，用下午茶时30楼行政酒廊的印度小姐姐carrie中文流利、热情大方，第二天早餐后还收到了全英文的祝福小卡片，下次还会入住。', '2024-07-03', 5, '[''餐饮设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233e12000eny75s57C84_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236s12000enxxek479CF_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌五星，环境服务一流。晚餐都在30楼行政酒廊解决，工作人员都很热情，就是出餐的', '老牌五星，环境服务一流。晚餐都在30楼行政酒廊解决，工作人员都很热情，就是出餐的种类可以再丰富一点就好了。', '2024-08-25', 5, '[''餐饮设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231w12000f8y266z175A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235512000f8yexjoFF14_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235d12000f8y3fnvCD26_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '入住广州花园酒店是我在广东住的最满意的酒店，一进大堂，富丽堂皇！虽然是老五星，很', '入住广州花园酒店是我在广东住的最满意的酒店，一进大堂，富丽堂皇！虽然是老五星，很有年代感，服务却很到位！后花园真的漂亮，小朋友特别喜欢，喷泉瀑布园林花草！特别是前台的小洪美女细心的在身份证上看到当天的生日，贴心的为我们免费升级了房间，让我们在酒店过了一个难忘的生日！真心感谢！还有迎宾的李雯美女，送了礼物给了我家的小朋友，谢谢你们！', '2025-03-23', 5, '[''前台服务'', ''整体满意度'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235d12000j9rs8b10667_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233p12000j9s1dtq13B0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234f12000j9ray9lCE58_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230z12000j9s1bp4DABB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232312000j9ripa3934F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店不错！', '酒店不错！', '2024-12-02', 4, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233212000gzwyoi1EDA4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234y12000gzxoqqg018E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231712000gzxgkij341A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店，名副其实！环境真的很美，酒店的每处的花艺设计都非常高级！尤其是瀑布餐厅', '花园酒店，名副其实！环境真的很美，酒店的每处的花艺设计都非常高级！尤其是瀑布餐厅，只能用哇塞来形容了??????拍照巨出片！
再来夸一下服务，从到酒店大门下车，从迎宾开始的每一位工作人员都很有耐心，满脸笑容！真的让我体会到了宾至如归的感觉！因为是zijiz人带着1岁多的宝宝，有的时候来不及照看宝宝的时候，大厅里的工作人员都会帮忙照顾，非常贴心！
虽然花园酒店是老牌五星酒店，但是房间设施还是一样很好！唯一的建议就是希望贵酒店能够提供儿童围栏就更加完美了！', '2024-07-13', 5, '[''整体满意度'', ''前台服务'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230s12000ergsov65807_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234p12000ergp7q8D3CB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236y12000ergpnpb9297_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236012000ergsb4s919A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232e12000ero0gc8F764_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235n12000erntfco2AC3_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '带爸妈一起出游，入住3晚的红棉套房，非常好的体验，前台的工作人员Winne We', '带爸妈一起出游，入住3晚的红棉套房，非常好的体验，前台的工作人员Winne Wei热情负责。

酒店保养了不错，比较新。打车去各景点都比较近，餐饮配套齐全，这点特别方便。留了一点小遗憾，来不及去打卡瀑布餐厅下午茶。', '2024-10-03', 5, '[''前台服务'', ''周边配套'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0234u12000fyatoe0AF18_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234l12000fy9iizb4969_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232112000fya7brhCBE6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230y12000fy94hl8A6FC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233x12000fy9g4li13CF_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '白金五星，确实很棒，虽然年份有点久，但是各方面服务都很好，很多航空公司机组人员都', '白金五星，确实很棒，虽然年份有点久，但是各方面服务都很好，很多航空公司机组人员都住这里
泳池游泳，服务生很快就送上清凉饮品，真棒', '2024-08-23', 5, '[''整体满意度'', ''公共设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232112000f86vhr0E3FF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236p12000f87d537AD99_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235h12000f878gzf7204_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234k12000f87dmk86180_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '中秋期间入住，十分令人惊喜的一家酒店，从前台Winnie的接待开始，就感受到了酒', '中秋期间入住，十分令人惊喜的一家酒店，从前台Winnie的接待开始，就感受到了酒店热情热心的高水准服务。客服服务员的整理和打扫非常细致，早上刷牙不小心打碎了漱口杯、立即来帮忙现场处理。临走还收到了楼层引导员小李的祝福和小礼物。餐厅服务体验了两天的下午茶歇，行政酒廊以及早餐，一楼的服务较顶楼略逊色一点点，但早餐的选择和品质都很不错，完全弥补了服务上的不足。顶楼的服务员都很漂亮温柔，服务也很细致
真的很推荐大家入住噢！', '2024-09-16', 5, '[''前台服务'', ''客房服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236112000fl7p8464A9D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232212000fl7d2qfC32E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233912000fl7xb894614_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间安排的非常好，早餐也很丰富，酒店内也是有可参观和玩的地方，附近有名的餐厅蛮多', '房间安排的非常好，早餐也很丰富，酒店内也是有可参观和玩的地方，附近有名的餐厅蛮多，不过酒店内的餐厅也很好。', '2024-11-13', 5, '[''餐饮设施'', ''周边配套'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236k12000gnyf0ji1DCF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233212000gnyfuldFD93_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231912000gnyf0jm6415_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '很不错的酒店，性价比很高。工作人员很热情，我们一家三口出行，还特意免费升级了房间', '很不错的酒店，性价比很高。工作人员很热情，我们一家三口出行，还特意免费升级了房间。贴心的给小朋友准备了儿童拖鞋，还多给了饮用水。', '2024-08-03', 5, '[''性价比'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233s12000ezolm5uB349_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230r12000ezoh3awE614_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235p12000ezobrphB46D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233v12000ezoc9iuA6F9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230812000ezobkws6416_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境很一般', '环境很一般', '2024-11-28', 2, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230h12000gwzct8rDB8E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '不愧是白金五星，不愧是花园酒店，服务很好，隔音也很好，比现在的新酒店真的不知道强', '不愧是白金五星，不愧是花园酒店，服务很好，隔音也很好，比现在的新酒店真的不知道强多少，感谢ceclia，看到我们带娃帮忙协调房间，酒店餐厅也都很好吃，第二天花园的桂花太香了，真的很推荐', '2025-01-09', 4, '[''整体满意度'', ''前台服务'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232p12000hoevwri0CE2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231q12000hoeqqt78FA8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235712000hoevwy4347D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231u12000hoewoux5CBF_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间设施非常好??前台服务小哥kasas服务也很周到，后花园很漂亮，大堂非常雅观', '房间设施非常好??前台服务小哥kasas服务也很周到，后花园很漂亮，大堂非常雅观！', '2025-04-05', 5, '[''房间设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231c12000jkxm4unCE48_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '满分好评，感谢Rebecca女士帮我们升级了套房房型，让旅行十分完美！@Rebe', '满分好评，感谢Rebecca女士帮我们升级了套房房型，让旅行十分完美！@Rebecca
老牌白金五星酒店，瀑布餐厅超级壮观。
最主要是房间整洁、宽敞，新中式的装修风格给人留下了深刻印象，电动窗帘和中式酒柜的设计也很别出心裁。
最重要的是这个窗边浴缸十分满意了，看着城景泡澡，一种闹中取静，大隐于市的感觉。', '2024-06-09', 5, '[''房间设施'', ''整体满意度'', ''景观/朝向'']', '["[ \"https://dimg04.c-ctrip.com/images/0234t12000eefthdl004E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232712000eefxz41BE99_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233v12000eefq8ya68A0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233s12000eefxeg8B492_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235112000eefsqvdAF61_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234c12000eeg499kD14B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '具歴史代表的五星酒店。', '具歴史代表的五星酒店。', '2024-12-21', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/02344224x8y5kb05n3CFC_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间整洁明亮，温馨舒适。服务热情周到，宾至如归。酒店位置好，出行方便。酒店竟然有', '房间整洁明亮，温馨舒适。服务热情周到，宾至如归。酒店位置好，出行方便。酒店竟然有瀑布和博物馆，很意外。大堂更是金碧辉煌，服务员还主动帮我们照了相。免费升级了房间和延时退房。体验很好很满意。', '2024-08-04', 5, '[''整体满意度'', ''前台服务'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0235g12000f04jtuw9E0C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233i12000f04620nABE1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234i12000f04k5h94879_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '来住过很多次了，各种房型都住过，非常舒适。服务很好，有求必应。这个位置去哪儿哪儿', '来住过很多次了，各种房型都住过，非常舒适。服务很好，有求必应。这个位置去哪儿哪儿也都方便。而且疫情后越来越热闹了，早餐也变得越来越好吃了。', '2024-07-24', 5, '[''整体满意度'', ''交通便利性'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/02302224x8vptv7va65A3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231l224x8vptvz0d6B98_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231d224x8vpttfy9A8DA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02314224x8vptv7vbFF2D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232h224x8vptwci7DB8C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店就在地铁出口处，出行非常方便，对面就有广州酒家，早午茶味道不错，价格也不', '花园酒店就在地铁出口处，出行非常方便，对面就有广州酒家，早午茶味道不错，价格也不贵。酒店的服务人员非常热情，有求必应，以后带家人还会再去哦', '2024-07-26', 4, '[''交通便利性'', ''周边配套'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235112000ewfk4qbC3EA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234k12000ewfo31a31FF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234h12000ewfjjbg1D6C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务很到位，环境很好', '服务很到位，环境很好', '2024-11-11', 5, '[''整体满意度'', ''前台服务'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232x12000gmcvyk107B7_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '很好，出差广州第二次选择了！酒店很有底蕴，酒店工作人员很礼貌，又给升级了房间，挺', '很好，出差广州第二次选择了！酒店很有底蕴，酒店工作人员很礼貌，又给升级了房间，挺好挺好！下次还会选择！', '2024-08-19', 5, '[''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235j12000f6gqslzEEAE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231912000f6gsiis0ED5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235i12000f6gqt61597A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '出差多年，五星级酒店也住过很多，第一次特别想写点评给花园酒店，不管是套房旋转餐厅', '出差多年，五星级酒店也住过很多，第一次特别想写点评给花园酒店，不管是套房旋转餐厅还是服务人员的服务态意识，水准都非常高！景色太棒了(ˉ▽ˉ)??，太适合我们这样出差没时间逛的客人了，酒吧乐队水平也很高，请每位喝了一瓶啤酒，性价比绝高，推荐给朋友100次(‐＾▽＾‐)??', '2024-05-30', 5, '[''整体满意度'', ''性价比'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234s12000e8qgpzt9FAC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230x12000e8r02e67F52_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232p12000e8r056gED09_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235h12000e8qvne6CF6B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230x12000e8qu5hr006F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232p12000e8r05e04F45_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230112000e8qe27v44F2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233l12000e8r056iDB19_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234i12000e8qnafeFE50_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这次总共入住4晚，可爱的前厅Virina小姐姐(名字拼写不知道有没有写错)让我们', '这次总共入住4晚，可爱的前厅Virina小姐姐(名字拼写不知道有没有写错)让我们用很优惠的价格升级到粤韵双床房，还送了早餐！
超级棒的入住体验，酒店出门就是地铁去哪都很方便。下次去广州还会选择花园酒店！', '2024-06-09', 5, '[''前台服务'', ''交通便利性'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233j12000ee05hamE3EC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231m12000ee053zjDF7C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234912000ee114zz839B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233u12000edzjjarD7CF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236b12000ee0hr03F387_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237012000ee0kxgeC46C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235m12000ee0c36569B8_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '体验非常好，不愧是老牌五星酒店，打卡过上海花园酒店，慕名来到广州花园酒店。感谢客', '体验非常好，不愧是老牌五星酒店，打卡过上海花园酒店，慕名来到广州花园酒店。感谢客房部姚师傅，非常细心周到，下次还会去', '2025-01-22', 5, '[''整体满意度'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236o12000hzukicj630C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235e12000hzupp3g77D9_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '和同事出差，一如既往的历史的沉淀的稳重的高级感。热情的服务，布置精美的鲜花出其不', '和同事出差，一如既往的历史的沉淀的稳重的高级感。热情的服务，布置精美的鲜花出其不意的出现在各个角落。健身房环境也很赞完成了一个5公里', '2024-09-05', 5, '[''整体满意度'', ''公共设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0230f12000fewetmjA171_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235o12000fewc5761E5A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '第一次住花园酒店，设施卫生环境都很好，前台的Viria非常nice，想人所想急人', '第一次住花园酒店，设施卫生环境都很好，前台的Viria非常nice，想人所想急人所急，表扬一下，老板该给加薪了。??因为不错的服务又续住了几晚，下次还会再来。', '2024-07-08', 5, '[''前台服务'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0234x12000epphwhr81C5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236412000epprkqx19EB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233p12000eppqzyv35D7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店是老牌的五星酒店了，地段就在闹市中心，大堂金碧辉煌，带一个大大的后花园，', '花园酒店是老牌的五星酒店了，地段就在闹市中心，大堂金碧辉煌，带一个大大的后花园，四楼还有一个酒店博物馆，酒店自带10家餐厅，可以说无敌方便了。30楼的旋转餐厅可以俯瞰360度风景，环境雅致，早餐品种很丰富，下午提供下午茶、五点后还有happy hour，来自印度的Carrie讲得一口流利的中文，笑容甜美，热心帮我们介绍了很多美食，还有美酒、现做的烤饼，还会热情跟小朋友互动，Aimee、Mignon服务效率特别高，还有Lina，都让人感受到宾至如归，一家人都留下难忘的美好回忆，下次还会再来的！', '2024-06-09', 5, '[''餐饮设施'', ''整体满意度'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0231u12000eeeo6wl33C1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235912000eeep36cF8D2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231w12000eeegvxt159D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232y12000eeeojmx8172_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231712000eeekpz91501_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店名不虚传！', '花园酒店名不虚传！', '2024-11-26', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236c12000gvu4b5s2559_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '一如既往的 喜欢花园酒家 ,每年都会入住的酒店', '一如既往的 喜欢花园酒家 ,每年都会入住的酒店', '2024-10-10', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233g12000g2ql0379123_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231y12000g2qm0ib14D0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '每次来广州都住这里，传统老钱五星酒店，花园酒店名不虚传，从硬件到服务都很在线。大', '每次来广州都住这里，传统老钱五星酒店，花园酒店名不虚传，从硬件到服务都很在线。大师贝聿铭设计的作品，如果有空去酒店花园里散散步非常惬意。', '2024-08-22', 5, '[''整体满意度'', ''公共设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235w12000f7e9ld4FB8D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231712000f7eloy1CAC3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231812000f7ebr2wFE67_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233p12000f7ei1h4EF7F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235m12000f7eg9s04066_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231812000f7ecjeb503A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236j12000f7ecknn6A72_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '干净整洁，位置也挺好，去哪儿都方便，后面有个大公园，散步好去处', '干净整洁，位置也挺好，去哪儿都方便，后面有个大公园，散步好去处', '2024-09-22', 5, '[''卫生状况'', ''交通便利性'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0207312000fox73yk6C5B_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0235k12000fox7o798021_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '喜欢前台接待Cassie，态度很好没有无烟房还给我升级了。很贴心… 爱了爱了', '喜欢前台接待Cassie，态度很好没有无烟房还给我升级了。很贴心… 爱了爱了', '2024-09-06', 5, '[''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232312000fferad4BFE3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232m12000ffesm094D6C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235412000ffey0yv1810_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '前台赠送了早餐，行政酒廊Carrie和Cathy，赠送了下午茶，非常周到热情。酒', '前台赠送了早餐，行政酒廊Carrie和Cathy，赠送了下午茶，非常周到热情。酒店很有历史韵味，值得打卡', '2024-08-11', 5, '[''前台服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234w12000f3511ed9E2A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230912000f3510r36BC3_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境优美没话说真的。每次出差必选花园酒店入住。前台有位叫什么来好像virIioi', '环境优美没话说真的。每次出差必选花园酒店入住。前台有位叫什么来好像virIioi戴眼镜的小姐姐非常细心温柔可爱型…哈哈我可能打错英文名。不好意思哈。', '2024-07-09', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0203i12000eqcc11uB61A_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0235j12000eqc1n3p1CEF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236p12000eqbtemoAE88_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间卫生干净服务很好热情周到，一楼西餐厅也不错就是太多美洲飞洲伊朗等外国人，周边', '房间卫生干净服务很好热情周到，一楼西餐厅也不错就是太多美洲飞洲伊朗等外国人，周边没什么可吃的离地铁比较近出门就是打车也方便门口就有很多', '2024-07-17', 5, '[''卫生状况'', ''交通便利性'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232v12000et5l7wk75E7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232o12000et5ithw9486_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232812000et5vz277A67_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231612000et5rly436C8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230912000et5qjp1965E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231x12000et5k13q7C84_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '强烈推荐花园酒店，在这里度过了非常愉快的时光。本来看了些差评有些犹豫，但酒店就在', '强烈推荐花园酒店，在这里度过了非常愉快的时光。本来看了些差评有些犹豫，但酒店就在地铁口，交通方便，而且由于是从天河区换到这边住，来不及再选了，就想先过来看看，事实证明来对了。一进门就被酒店大堂吸引，中西合璧的布置非常漂亮，工作人员很多但井然有序。前台办理入住的viria小姐姐人美心善，专业高效，很快就办好了手续，主动升级了套房，住的非常舒心，还送了行政酒廊的下午茶，非常感谢。一整天一直在下雨，懒得出门，但行政酒廊的食材新鲜，服务超好，也是很好的体验，mignon一直在介绍酒店各个餐厅，推荐各类饮品和餐食，还按照我的要求，特调了一杯很清淡的酒，非常好喝。Carrie是一个印度小姐姐，聊了一会儿weather，aimee和lina也非常热情周到！早餐在旋转餐厅吃的，俯瞰下去景色很美，小哥哥们服务周到。雨停了，去花园转了一圈，步步有景，鱼很漂亮也很肥，很多人拍照。4层的博物馆比想象中大而全，不仅有酒店的历史，也有些广州的历史和酒店行业的发展史。', '2024-06-02', 5, '[''前台服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233v12000ea5scmuD3C8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231t12000ea64e5kE23B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236b12000ea613h93442_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236912000ea61jx8AB55_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店老牌五星，大厅很大气，房间很好，前台小姐姐ANN免费升级了房间，唯一就是停车', '酒店老牌五星，大厅很大气，房间很好，前台小姐姐ANN免费升级了房间，唯一就是停车场在边上，要走几步。', '2024-08-12', 5, '[''前台服务'', ''公共设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233e12000f3ka90d3CF2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231l12000f3kac4s95E6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '旧地重游『白金五星级酒店』：广州花园酒店，园林的建筑景观，定会让你宾至如归。每次', '旧地重游『白金五星级酒店』：广州花园酒店，园林的建筑景观，定会让你宾至如归。每次下榻位于闹中取静的市中心——花园酒店，都能给我一种好温馨的感觉。在这里，我遇到了酒店行政酒廊的Carrie姐姐和她的同事Aimee，得知我们是一家人来城央度假为我们的其中一间房间升级为粤韵房和给了我们一家人的行政酒廊使用权。这次的行政酒廊是在30楼，凌旋阁广州最大的旋转餐厅——可容纳两千多人同时进餐的凌旋阁，北眺云山，南望珠水，可以尽览广州的景色。早餐选择丰富且中西结合。同行老人家都不得不赞叹一个字“靓”。用餐过程中行政酒廊的Carrie姐姐会不定时过来询问是否需要帮助，入住期间还去了后花园观赏锦鲤，感觉“老朋友”都被养得胖嘟嘟了。在这里，Carrie姐姐和Aimee的服务很好的诠释了白金五星级酒店的水平。再次感谢您们对我们一家的款待。期待下次再见！', '2024-05-19', 5, '[''前台服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236u12000e2jzvkgF44E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232i12000e2jzyz1585F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230212000e2jzv2f8EBB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233a12000e2k00oiBC72_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231t12000e2k007g8E18_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231012000e2k008q7B1F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236912000e2k189z7F8A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231w12000e2k03wk3C0C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233c12000e2k02niD1B2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '豪华大气、服务好', '豪华大气、服务好', '2024-11-15', 4, '[''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0230812000gp66ga39036_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233312000gp5uojjAD74_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235o12000gp61pog6A34_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234r12000gp5vbn988A6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '一如既往的好… 房间不错 …服务好…', '一如既往的好… 房间不错 …服务好…', '2024-12-18', 5, '[''整体满意度'', ''房间设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235t12000h9ifmngF689_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235t12000h9hw6sy7554_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '白金五星级，名副其实。值得再去哦。', '白金五星级，名副其实。值得再去哦。', '2024-11-10', 5, '[''整体满意度'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0233112000gllf7ac2641_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233u12000gll16ih9620_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234q12000gll16ijF963_R_150_150_R5_Q70_D.jpg\" ]"]');